Comparable: orden NATURAL de una clase (implementa compareTo).
Comparator: orden ALTERNATIVO (clase separada).

// Comparable
class Alumno implements Comparable<Alumno> {
    int nia;
    public int compareTo(Alumno o) { return this.nia - o.nia; }
}

// Comparator
class PorEdad implements Comparator<Alumno> {
    public int compare(Alumno a, Alumno b) { return a.edad - b.edad; }
}

Collections.sort(lista);                   // usa Comparable
Collections.sort(lista, new PorEdad());    // usa Comparator

