throws: DECLARA que un metodo puede lanzar una excepcion (en la firma).
throw: LANZA explicitamente una excepcion (en el cuerpo).

// throws en la firma: quien llama debe manejar la excepcion
static void leerArchivo(String ruta) throws IOException, FileNotFoundException {
    if (ruta == null) {
        throw new IllegalArgumentException("Ruta no puede ser null");
    }
    FileReader file = new FileReader(ruta);
}

// throw para lanzar la excepcion
static void validarEdad(int edad) {
    if (edad < 0 || edad > 150) {
        throw new IllegalArgumentException("Edad no valida: " + edad);
    }
}

throws se usa con EXCEPCIONES VERIFICADAS (checked).
